+}
+"#;
+
+/// Extension that returns null from event hook (no-op).
+const NOOP_EVENT_EXT: &str = r#"
+export default function activate(pi) {
+    pi.events("register", {
+        name: "noop-ext",
+        hooks: ["before_agent_start"]
+    });
