+        event: "before_agent_start",
+        handler: () => null
+    });
+}
+"#;
+
+/// Extension that returns a rejected promise from event hook.
+const REJECTED_PROMISE_EXT: &str = r#"
+export default function activate(pi) {
+    pi.events("register", {
