+#[derive(Debug, Clone, Serialize)]
+struct BenchRecord {
+    schema: String,
+    runtime: String,
+    scenario: String,
+    extension: String,
+    runs: usize,
+    summary: Summary,
+    elapsed_ms: f64,
+    per_call_us: f64,
+    calls_per_sec: f64,
+    env: EnvFingerprint,
+    timestamp: String,
+}
+
+fn emit_jsonl_line(record: &BenchRecord) -> String {
+    serde_json::to_string(record).unwrap_or_default()
